#!/usr/bin/env node
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// AI文章生成（调用OpenClaw的子代理）
async function generatePost() {
  const topics = [
    'AI编程助手的发展趋势',
    'WebAssembly在浏览器中的应用',
    'CSS新特性探索',
    'JavaScript性能优化技巧',
    '前端工程化实践',
    '无障碍访问(A11y)指南',
    'Web组件化开发',
    'TypeScript高级类型',
    'Tailwind CSS最佳实践',
    'Web性能监控'
  ];

  const topic = topics[Math.floor(Math.random() * topics.length)];
  const now = new Date();
  const pad = (n) => String(n).padStart(2, '0');
  const dateStr = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;

  console.log(`🤖 正在生成文章: ${topic}...`);

  // 调用OpenClaw子代理生成文章内容
  const { spawn } = require('child_process');
  const child = spawn('openclaw', ['sessions_spawn', '--task', `为博客写一篇关于"${topic}"的文章，包含技术要点和实践建议，字数800-1000字，使用中文`, '--runtime', 'subagent'], {
    stdio: ['pipe', 'pipe', 'pipe']
  });

  let output = '';
  child.stdout.on('data', (data) => {
    output += data.toString();
  });

  child.stderr.on('data', (data) => {
    console.error('生成过程:', data.toString());
  });

  return new Promise((resolve, reject) => {
    child.on('close', (code) => {
      if (code === 0) {
        resolve(output);
      } else {
        reject(new Error(`生成失败，退出码: ${code}`));
      }
    });
  });
}

// 创建文章文件
function createPost(title, content) {
  const now = new Date();
  const pad = (n) => String(n).padStart(2, '0');
  const dateStr = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
  const slug = title.replace(/[^\w\u4e00-\u9fff]+/g, '-').toLowerCase();

  const dir = path.join(__dirname, '..', 'src', 'content', 'blog');
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  const frontmatter = `---
title: '${title}'
description: '${title}的描述'
date: ${dateStr}
tags: []
categories: ['技术文章']
toc: true
comment: true
reward: false
---

${content}
`;

  fs.writeFileSync(path.join(dir, `${slug}.md`), frontmatter);
  return slug;
}

// 主流程
async function main() {
  try {
    console.log('🕐 开始自动文章撰写流程...\n');

    // 1. 生成文章内容
    const content = await generatePost();

    // 2. 创建文章
    const slug = createPost('AI自动生成的技术文章', content);

    console.log(`\n✅ 文章已创建: ${slug}.md`);
    console.log('📝 下一步：提交并部署到GitHub Pages');

    // 3. 提交到Git
    execSync('git add .', { cwd: path.join(__dirname, '..'), stdio: 'inherit' });
    execSync(`git commit -m "feat: 自动生成文章 ${slug}.md"`, { cwd: path.join(__dirname, '..'), stdio: 'inherit' });
    execSync('git push', { cwd: path.join(__dirname, '..'), stdio: 'inherit' });

    console.log('\n🎉 自动文章撰写流程完成！文章已推送到GitHub');
  } catch (error) {
    console.error('\n❌ 错误:', error.message);
    process.exit(1);
  }
}

main();

#!/usr/bin/env node
const { spawn } = require('child_process');
const fs = require('fs');
const path = require('path');

// AI文章生成（调用OpenClaw的子代理）
async function generatePost(topic) {
  console.log(`🤖 正在生成文章: ${topic}...`);

  // 调用OpenClaw子代理生成文章内容
  const child = spawn('openclaw', ['sessions_spawn', '--task', `为博客写一篇关于"${topic}"的技术文章，包含技术要点和实践建议，字数800-1000字，使用中文，使用markdown格式`, '--runtime', 'subagent'], {
    stdio: ['pipe', 'pipe', 'pipe'],
    shell: true
  });

  let output = '';
  let errorOutput = '';

  child.stdout.on('data', (data) => {
    const text = data.toString();
    output += text;
    // 只输出关键信息，不输出完整的子代理输出
    if (text.includes('文章') || text.includes('内容') || text.includes('完成')) {
      process.stdout.write(text);
    }
  });

  child.stderr.on('data', (data) => {
    errorOutput += data.toString();
  });

  return new Promise((resolve, reject) => {
    child.on('close', (code) => {
      if (code === 0) {
        resolve(output);
      } else {
        console.error('\n生成过程错误:', errorOutput);
        reject(new Error(`生成失败，退出码: ${code}`));
      }
    });

    // 5分钟后超时
    setTimeout(() => {
      child.kill();
      reject(new Error('生成超时'));
    }, 5 * 60 * 1000);
  });
}

// 创建文章文件
function createPost(title, content) {
  const now = new Date();
  const pad = (n) => String(n).padStart(2, '0');
  const dateStr = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
  const slug = title.replace(/[^\w\u4e00-\u9fff]+/g, '-').toLowerCase();

  const dir = path.join(__dirname, '..', 'src', 'content', 'blog');
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  const frontmatter = `---
title: '${title}'
description: '${title}的描述'
date: ${dateStr}
tags: []
categories: ['技术文章']
toc: true
comment: true
reward: false
---

${content}
`;

  fs.writeFileSync(path.join(dir, `${slug}.md`), frontmatter);
  return slug;
}

// 主流程
async function main() {
  const topics = [
    'AI编程助手的发展趋势',
    'WebAssembly在浏览器中的应用',
    'CSS新特性探索',
    'JavaScript性能优化技巧',
    '前端工程化实践',
    '无障碍访问(A11y)指南',
    'Web组件化开发',
    'TypeScript高级类型',
    'Tailwind CSS最佳实践',
    'Web性能监控'
  ];

  try {
    console.log('🕐 开始自动文章撰写流程...\n');

    // 1. 随机选择主题
    const topic = topics[Math.floor(Math.random() * topics.length)];
    console.log(`📌 主题: ${topic}\n`);

    // 2. 生成文章内容
    const content = await generatePost(topic);

    // 3. 创建文章
    const slug = createPost('AI自动生成的技术文章', content);

    console.log(`\n✅ 文章已创建: ${slug}.md`);
    console.log('📝 下一步：提交并部署到GitHub Pages');

    // 4. 提交到Git
    const cwd = path.join(__dirname, '..');
    execSync('git add .', { cwd, stdio: 'inherit' });
    execSync(`git commit -m "feat: 自动生成文章 ${slug}.md"`, { cwd, stdio: 'inherit' });
    execSync('git push', { cwd, stdio: 'inherit' });

    console.log('\n🎉 自动文章撰写流程完成！文章已推送到GitHub');
    console.log('🔗 GitHub Pages将在几分钟内自动部署');
  } catch (error) {
    console.error('\n❌ 错误:', error.message);
    process.exit(1);
  }
}

// 简单的execSync封装
function execSync(command, options) {
  return require('child_process').execSync(command, {
    ...options,
    stdio: options.stdio || 'inherit',
    shell: true
  });
}

main();

