  if (e.target.classList.contains('item')) {
    handleClick(e.target);
  }
});
```

## 3. 避免内存泄漏

内存泄漏会导致应用性能逐渐下降，最终崩溃。

### 及时清理定时器和事件监听器

```javascript
let timer;

function startWork() {
  timer = setInterval(doWork, 1000);
}

function stopWork() {
  clearInterval(timer);
  timer = null;
}

// 组件卸载时清理
componentWillUnmount() {
  this.timer && clearInterval(this.timer);
  window.removeEventListener('resize', this.handleResize);
}
```

## 4. 使用Web Workers处理复杂计算

将CPU密集型任务移至Web Worker，避免阻塞主线程。

```javascript
// main.js
const worker = new Worker('worker.js');

worker.postMessage({ data: largeArray });

worker.onmessage = (e) => {
  console.log('计算结果:', e.data);
};

// worker.js
self.onmessage = (e) => {
  const result = heavyComputation(e.data);
  self.postMessage(result);
};
```

## 5. 优化循环和算法

选择合适的数据结构和算法对性能至关重要。

### 使用Map替代对象进行频繁查找

```javascript
// ❌ 低效：对象查找
const userMap = {};
users.forEach(user => {
  userMap[user.id] = user;
});
// 查找：O(1) 但对象属性遍历较慢

// ✅ 高效：Map查找
const userMap = new Map();
users.forEach(user => {
  userMap.set(user.id, user);
});
// 查找：O(1) 且遍历更快
```

### 避免在循环中创建函数

```javascript
// ❌ 低效：每次循环创建新函数
buttons.forEach(btn => {
  btn.addEventListener('click', () => {
    console.log(btn.id);
  });
});

// ✅ 高效：使用bind或箭头函数
buttons.forEach(btn => {
  btn.addEventListener('click', function() {
    console.log(this.id);
  });
});
```

## 6. 代码分割和懒加载

减少初始加载时间，提升用户体验。

```javascript
// 使用动态导入进行代码分割
const loadComponent = () => import('./HeavyComponent');

button.addEventListener('click', async () => {
  const module = await loadComponent();
  module.render();
});

// 路由懒加载
const routes = [
  {
    path: '/dashboard',
    component: () => import('./Dashboard')
  },
  {
    path: '/settings',
    component: () => import('./Settings')
  }
];
```

## 7. 使用虚拟滚动

当渲染大量列表时，虚拟滚动只渲染可见区域的项目。

```javascript
import { FixedSizeList } from 'react-window';

const VirtualList = () => (
  <FixedSizeList
    height={600}
    itemCount={10000}
    itemSize={50}
    width={400}
  >
    {({ index, style }) => (
      <div style={style}>Item {index}</div>
    )}
  </FixedSizeList>
);
```

## 8. 性能监控和分析

使用开发工具持续监控性能。

```javascript
// 使用Performance API
const startTime = performance.now();

// 执行操作
doHeavyWork();

const endTime = performance.now();
console.log(`操作耗时: ${(endTime - startTime).toFixed(2)}ms`);

// 使用Chrome DevTools
// 1. 打开Performance面板
// 2. 点击Record开始录制
// 3. 执行操作
// 4. 停止录制并分析
```

## 实践建议

1. **优先优化关键路径**：识别并优化用户最常使用的功能
2. **建立性能基准**：记录关键性能指标，持续监控改进
3. **渐进增强**：先确保基础功能正常，再添加高级特性
4. **定期代码审查**：发现并修复性能问题
5. **使用性能工具**：利用Lighthouse、Webpack Bundle Analyzer等工具

## 总结

JavaScript性能优化是一个持续的过程，需要开发者不断学习和实践。通过合理使用DOM操作、事件委托、Web Workers、代码分割等技术，可以显著提升应用的性能和用户体验。记住，性能优化不是一次性的任务，而是贯穿整个开发周期的最佳实践。

## 参考资源

- [MDN Web Performance](https://developer.mozilla.org/en-US/docs/Web/Performance)
- [JavaScript性能优化最佳实践](https://github.com/addyosmani/1kb-js-optimizations)
- [Chrome DevTools Performance](https://developer.chrome.com/docs/devtools/performance/)

