#!/usr/bin/env node
const { spawn } = require('child_process');
const fs = require('fs');
const path = require('path');

// AI文章生成（调用OpenClaw的子代理）
async function generatePost(topic) {
  console.log(`🤖 正在生成文章: ${topic}...`);

  // 调用OpenClaw子代理生成文章内容
  const child = spawn('openclaw', ['sessions_spawn', '--task', `为博客写一篇关于"${topic}"的技术文章，包含技术要点和实践建议，字数800-1000字，使用中文，使用markdown格式`, '--runtime', 'subagent'], {
    stdio: ['pipe', 'pipe', 'pipe'],
    shell: true
  });

  let output = '';
  let errorOutput = '';

  child.stdout.on('data', (data) => {
    const text = data.toString();
    output += text;
    // 只输出关键信息，不输出完整的子代理输出
    if (text.includes('文章') || text.includes('内容') || text.includes('完成')) {
      process.stdout.write(text);
    }
  });

  child.stderr.on('data', (data) => {
    errorOutput += data.toString();
  });

  return new Promise((resolve, reject) => {
    child.on('close', (code) => {
      if (code === 0) {
        resolve(output);
      } else {
        console.error('\n生成过程错误:', errorOutput);
        reject(new Error(`生成失败，退出码: ${code}`));
      }
    });

    // 5分钟后超时
    setTimeout(() => {
      child.kill();
      reject(new Error('生成超时'));
    }, 5 * 60 * 1000);
  });
}

