title: '${title}'
description: '${title}的描述'
date: ${dateStr}
tags: []
categories: ['技术文章']
toc: true
comment: true
reward: false
---

${content}
`;

  fs.writeFileSync(path.join(dir, `${slug}.md`), frontmatter);
  return slug;
}

